{"code":"import json, re
# Load UNIV CALIFORNIA records
path_univ = var_call_5hfOOzVekj2vU7HdE07OAzBp
with open(path_univ, 'r', encoding='utf-8') as f:
    univ_data = json.load(f)
# Extract publication numbers from Patents_info
pat_pattern = re.compile(r"\b[A-Z]{2}-[0-9A-Z\-]{4,}\b")
univ_pub_nums = set()
for rec in univ_data:
    pi = rec.get('Patents_info','')
    for m in pat_pattern.findall(pi):
        univ_pub_nums.add(m)
# Also try to find publication numbers in other fields like citation
for rec in univ_data:
    cit = rec.get('citation','')
    try:
        citlist = json.loads(cit)
        for c in citlist:
            pn = c.get('publication_number')
            if pn:
                univ_pub_nums.add(pn)
    except Exception:
        for m in pat_pattern.findall(cit):
            univ_pub_nums.add(m)
univ_pub_nums = set([u for u in univ_pub_nums if u])

# Load all records that have citations (from previous query)
path_citing = var_call_ve2g86unmpIwbOrX6CUCNLSm
with open(path_citing, 'r', encoding='utf-8') as f:
    citing_data = json.load(f)

assignee_to_cpcs = {}
all_cpc_codes = set()
# pattern to extract assignee name
assignee_pattern = re.compile(r"^(.*?)(?:\s+(?:holds|has|is assigned to|assigned to|is owned by|owns|is held by|is the owner of|owned by)\b)", re.IGNORECASE)

for rec in citing_data:
    cit = rec.get('citation','')
    try:
        citlist = json.loads(cit)
    except Exception:
        # skip malformed
        continue
    cited = False
    for c in citlist:
        pn = c.get('publication_number')
        if pn and pn in univ_pub_nums:
            cited = True
            break
    if not cited:
        # also check by substring
        for pn in univ_pub_nums:
            if pn in cit:
                cited = True
                break
    if cited:
        pi = rec.get('Patents_info','')
        assignee = None
        m = assignee_pattern.search(pi)
        if m:
            assignee = m.group(1).strip()
        else:
            # fallback: take up to first comma
            assignee = pi.split(',')[0].strip()
        # clean common leading words
        assignee = assignee.strip()
        # get primary cpc
        cpc_field = rec.get('cpc','')
