                first = cpc_list[0]
                if isinstance(first, dict):
                    primary_code = first.get('code')
        except Exception:
            # try to find first code via regex
            pm = pat_pattern.search(cpc_field)
            if pm:
                primary_code = pm.group(0)
        if not assignee:
            assignee = 'UNKNOWN'
        if not primary_code:
            primary_code = 'UNKNOWN'
        assignee_to_cpcs.setdefault(assignee, set()).add(primary_code)
        if primary_code and primary_code!='UNKNOWN':
            all_cpc_codes.add(primary_code)

