path_univ = var_call_5hfOOzVekj2vU7HdE07OAzBp
path_all_citing = var_call_VsGPdmNLU1uADIrH8TCgWVlT
with open(path_univ, 'r', encoding='utf-8') as f:
    univ_data = json.load(f)
with open(path_all_citing, 'r', encoding='utf-8') as f:
    citing_data = json.load(f)

# regex for publication-like tokens
pat = re.compile(r"\b[A-Z]{2}-[0-9A-Z\-]{4,}\b")
# build univ publication numbers
univ_pub_nums = set()
for rec in univ_data:
    pi = rec.get('Patents_info','')
    matches = pat.findall(pi)
    if matches:
        # pick last match as publication number (heuristic)
        univ_pub_nums.add(matches[-1])
# also try to find publication numbers inside citation fields of univ records
for rec in univ_data:
    cit = rec.get('citation','')
    try:
        cl = json.loads(cit)
        for c in cl:
            pn = c.get('publication_number')
            if pn:
                univ_pub_nums.add(pn)
    except Exception:
        for m in pat.findall(cit):
            univ_pub_nums.add(m)

# Clean empty
univ_pub_nums = {u for u in univ_pub_nums if u}

# Now find citing records that cite any of these publication numbers
assignee_pattern = re.compile(r"^(.*?)(?:\s+(?:holds|has|is assigned to|assigned to|is owned by|owns|is held by|is the owner of|owned by|is assigned|assigned)\b)", re.IGNORECASE)
assignee_primary = []  # list of tuples (assignee, primary_code)
primary_codes_set = set()

for rec in citing_data:
    cit_raw = rec.get('citation','')
    try:
        citlist = json.loads(cit_raw)
    except Exception:
        citlist = []
    cites_univ = False
    for c in citlist:
        pn = c.get('publication_number','')
        if pn and pn in univ_pub_nums:
            cites_univ = True
            break
    if not cites_univ:
        # substring fallback
        for pn in univ_pub_nums:
            if pn and pn in cit_raw:
                cites_univ = True
                break
    if not cites_univ:
        continue
    # extract assignee
    pi = rec.get('Patents_info','')
    m = assignee_pattern.search(pi)
    if m:
        assignee = m.group(1).strip()
    else:
        assignee = (pi.split(',')[0] or '').strip()
    if not assignee:
        assignee = 'UNKNOWN'
    if 'UNIV CALIFORNIA' in assignee.upper():
        continue
    # extract primary cpc code
    primary = None
    cpc_field = rec.get('cpc','')
    try:
        cpcs = json.loads(cpc_field)
        if isinstance(cpcs, list) and cpcs:
            for e in cpcs:
                if isinstance(e, dict) and e.get('first'):
                    primary = e.get('code')
                    break
            if not primary and isinstance(cpcs[0], dict):
                primary = cpcs[0].get('code')
    except Exception:
        pass
    if not primary:
        # try regex capture of a code-like (letters+digits and slash)
        m2 = re.search(r"[A-Z]{1,3}\d*[A-Z]*/\d+|[A-Z]\d+/\d+|[A-Z]{1,3}\d*/\d+", cpc_field)
        if m2:
            primary = m2.group(0)
    if not primary:
        primary = 'UNKNOWN'
    assignee_primary.append((assignee, primary))
    if primary!='UNKNOWN':
        primary_codes_set.add(primary)

# Deduplicate assignees: keep unique assignee-primary pairs
unique = {}
for a, p in assignee_primary:
    unique.setdefault(a, set()).add(p)

# Prepare output
out = {'univ_pub_count': len(univ_pub_nums), 'univ_pub_sample': sorted(list(univ_pub_nums))[:50], 'assignee_map': {k: sorted(list(v)) for k,v in unique.items()}, 'primary_codes': sorted(list(primary_codes_set))}
print('__RESULT__:')
print(json.dumps(out))"}

